const problemsDataPath = path.resolve(__dirname, '../../data/problems.json');
let problems = [];
try {
  const rawData = fs.readFileSync(problemsDataPath, 'utf8');
  problems = JSON.parse(rawData);
} catch (e) {
  problems = [];
}

/**
 * List problems with filtering, paging, and metadata.
 * @param {Object} options
 * @param {string} [options.difficulty] - Filter by difficulty (e.g. 'Easy', 'Medium', 'Hard')
 * @param {number} [options.limit=50] - Max number of results to return (max 50)
 * @param {boolean} [options.includeComponents=false] - Whether to include sorted componentLanguages
 * @returns {Object} result
 * {
 *   problems: Array,
 *   totalProblems: number,
 *   filteredCount: number,
 *   appliedLimit: number,
 *   difficultyBreakdown: { [difficulty]: number }
 * }
 */
function listProblems({ difficulty, limit = 50, includeComponents = false } = {}) {
  // Validate limit
  if (typeof limit !== 'number' || limit <= 0) {
    limit = 50;
  }
  if (limit > 50) {
    limit = 50;
  }

  // Calculate difficulty breakdown for all problems
  const difficultyBreakdown = problems.reduce((acc, p) => {
    const d = p.difficulty || 'Unknown';
    acc[d] = (acc[d] || 0) + 1;
    return acc;
  }, {});

  // Filter by difficulty if provided
  let filtered = problems;
  if (difficulty) {
    filtered = problems.filter(p => p.difficulty === difficulty);
  }

  // Sort by roundId ascending (deterministic ordering)
  filtered.sort((a, b) => {
    if (a.roundId < b.roundId) return -1;
    if (a.roundId > b.roundId) return 1;
    return 0;
  });

  const filteredCount = filtered.length;
  const appliedLimit = Math.min(limit, filteredCount);

  // Slice to limit
  const sliced = filtered.slice(0, appliedLimit);

  // If includeComponents, add sorted componentLanguages array
  const problemsWithComponents = sliced.map(p => {
    const copy = { ...p };
    if (includeComponents && Array.isArray(copy.componentLanguages)) {
      copy.componentLanguages = [...copy.componentLanguages].sort();
    }
    return copy;
  });

  return {
    problems: problemsWithComponents,
    totalProblems: problems.length,
    filteredCount,
    appliedLimit,
    difficultyBreakdown
  };
}

module.exports = {
  listProblems
};
